AND EXISTS ( SELECT 1 FROM WK_USER_LRN_STS W_F LEFT JOIN PRGRT_TO_STS C_F ON C_F.SBJCT_ID = W_F.SBJCT_ID WHERE W_F.USER_ID = U.USER_ID
AND W_F.WKNO >= #{absnWknoFrom}
AND W_F.WKNO <= #{absnWknoTo}
AND CASE WHEN W_F.LRN_PRGRT >= NVL(C_F.ATND_MIN_PRGRT, 80) THEN 0 WHEN W_F.LRN_PRGRT >= NVL(C_F.LATE_MIN_PRGRT, 60) THEN 0 ELSE 1 END = 1 )

mapper.select:
SELECT COUNT(*) FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_USER B ON A.PROF_ID = B.USER_ID LEFT JOIN TB_LMS_DEPT D ON A.DEPT_ID = D.DEPT_ID WHERE NVL(A.DELYN, 'N') = 'N' AND A.SBJCT_YR = #{searchYr} AND TRIM(A.SBJCT_SMSTR) IN (#{searchSmstr}, LPAD(#{searchSmstr}, 2, '0')) AND (B.ORG_ID = #{orgId} OR B.ORG_ID IS NULL)
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_ID = #{deptId}
AND A.SBJCT_ID = #{sbjctId}
AND ( A.SBJCTNM LIKE '%' || #{searchKeyword} || '%' OR A.CRCLMN_NO LIKE '%' || #{searchKeyword} || '%' OR D.DEPTNM LIKE '%' || #{searchKeyword} || '%' OR B.USERNM LIKE '%' || #{searchKeyword} || '%' )

SELECT A.SBJCT_ID AS sbjctId , A.SBJCTNM AS sbjctnm , A.CRCLMN_NO AS crclmnNo , A.DVCLAS_NO AS dvclasNo FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_USER B ON A.PROF_ID = B.USER_ID WHERE NVL(A.DELYN, 'N') = 'N' AND A.SBJCT_YR = #{searchYr} AND TRIM(A.SBJCT_SMSTR) IN (#{searchSmstr}, LPAD(#{searchSmstr}, 2, '0')) AND (B.ORG_ID = #{orgId} OR B.ORG_ID IS NULL)
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_ID = #{deptId}
ORDER BY A.SBJCTNM ASC, A.DVCLAS_NO ASC

SELECT * FROM ( SELECT ROWNUM AS rnum, X.* FROM ( SELECT ROW_NUMBER() OVER( ORDER BY A.SBJCT_YR DESC, TRIM(A.SBJCT_SMSTR) DESC, A.SBJCTNM ASC ) AS lineNo , A.SBJCT_ID AS sbjctId , A.SBJCT_YR AS sbjctYr , TRIM(A.SBJCT_SMSTR) AS sbjctSmstr , A.DEPT_ID AS deptId , D.DEPTNM AS deptnm , A.CRCLMN_NO AS crclmnNo , A.SBJCTNM AS sbjctnm , A.DVCLAS_NO AS dvclasNo , A.DVCLAS_NCKNM AS dvclasNcknm , A.CRDTS AS crdts , B.USERNM AS usernm , A.SMSTR_CHRT_ID AS smstrChrtId , A.USEYN AS useyn , ( SELECT LISTAGG(U2.USERNM, ', ') WITHIN GROUP (ORDER BY SA.SBJCT_ADM_SEQNO) FROM TB_LMS_SBJCT_ADM SA JOIN TB_LMS_USER U2 ON U2.USER_ID = SA.USER_ID WHERE SA.SBJCT_ID = A.SBJCT_ID AND SA.SBJCT_ADM_TYCD = 'TUT' ) AS tutor , NULL AS asst , O.ORGNM AS orgNm FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_USER B ON A.PROF_ID = B.USER_ID LEFT JOIN TB_LMS_DEPT D ON A.DEPT_ID = D.DEPT_ID LEFT JOIN TB_LMS_ORG O ON O.ORG_ID = B.ORG_ID WHERE NVL(A.DELYN, 'N') = 'N' AND A.SBJCT_YR = #{searchYr} AND TRIM(A.SBJCT_SMSTR) IN (#{searchSmstr}, LPAD(#{searchSmstr}, 2, '0')) AND (B.ORG_ID = #{orgId} OR B.ORG_ID IS NULL)
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_ID = #{deptId}
AND A.SBJCT_ID = #{sbjctId}
AND ( A.SBJCTNM LIKE '%' || #{searchKeyword} || '%' OR A.CRCLMN_NO LIKE '%' || #{searchKeyword} || '%' OR D.DEPTNM LIKE '%' || #{searchKeyword} || '%' OR B.USERNM LIKE '%' || #{searchKeyword} || '%' )
) X WHERE ROWNUM <= (#{firstIndex} + #{listScale}) ) WHERE rnum > #{firstIndex}

WITH ,
SELECT ROW_NUMBER() OVER(ORDER BY U.STDNT_NO ASC) AS lineNo , U.USER_ID AS userId , U.USERNM AS usernm , U.STDNT_NO AS stdntNo , D.DEPTNM AS deptnm , NULL AS entyR , NULL AS scyr , MAX(CASE WHEN W.WKNO = 1 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk1Sts , MAX(CASE WHEN W.WKNO = 2 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk2Sts , MAX(CASE WHEN W.WKNO = 3 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk3Sts , MAX(CASE WHEN W.WKNO = 4 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk4Sts , MAX(CASE WHEN W.WKNO = 5 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk5Sts , MAX(CASE WHEN W.WKNO = 6 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk6Sts , MAX(CASE WHEN W.WKNO = 7 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk7Sts , MAX(CASE WHEN W.WKNO = 8 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk8Sts , MAX(CASE WHEN W.WKNO = 9 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk9Sts , MAX(CASE WHEN W.WKNO = 10 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk10Sts , MAX(CASE WHEN W.WKNO = 11 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk11Sts , MAX(CASE WHEN W.WKNO = 12 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk12Sts , MAX(CASE WHEN W.WKNO = 13 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk13Sts , MAX(CASE WHEN W.WKNO = 14 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk14Sts , MAX(CASE WHEN W.WKNO = 15 THEN CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 'O' WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) THEN '△' ELSE 'X' END END) AS wk15Sts , SUM(CASE WHEN W.LRN_PRGRT >= NVL(C.ATND_MIN_PRGRT,80) THEN 1 ELSE 0 END) AS atndCnt , SUM(CASE WHEN W.LRN_PRGRT >= NVL(C.LATE_MIN_PRGRT,60) AND W.LRN_PRGRT < NVL(C.ATND_MIN_PRGRT,80) THEN 1 ELSE 0 END) AS lateCnt , COALESCE(AB.ABSNCE_CNT, 0) AS absnCnt FROM TB_LMS_ATNDLC E JOIN TB_LMS_USER U ON U.USER_ID = E.USER_ID JOIN TB_LMS_DEPT D ON D.DEPT_ID = U.DEPT_ID LEFT JOIN WK_USER_LRN_STS W ON W.USER_ID = U.USER_ID LEFT JOIN PRGRT_TO_STS C ON C.SBJCT_ID = W.SBJCT_ID LEFT JOIN ( SELECT W2.USER_ID , SUM( CASE WHEN W2.LRN_PRGRT >= NVL(C2.ATND_MIN_PRGRT, 80) THEN 0 WHEN W2.LRN_PRGRT >= NVL(C2.LATE_MIN_PRGRT, 60) THEN 0 ELSE 1 END ) AS ABSNCE_CNT FROM WK_USER_LRN_STS W2 LEFT JOIN PRGRT_TO_STS C2 ON C2.SBJCT_ID = W2.SBJCT_ID GROUP BY W2.USER_ID ) AB ON AB.USER_ID = U.USER_ID WHERE E.SBJCT_ID = #{sbjctId}
GROUP BY U.USER_ID, U.USERNM, U.STDNT_NO, D.DEPTNM, COALESCE(AB.ABSNCE_CNT, 0) ORDER BY U.STDNT_NO ASC

WITH BASE_STDNT AS ( SELECT DISTINCT USER_ID FROM TB_LMS_ATNDLC WHERE SBJCT_ID = #{sbjctId} ), ASMT_TOT AS ( SELECT COUNT(DISTINCT ASMT_ID) AS ASMT_TOT_CNT FROM TB_LMS_ASMT WHERE SBJCT_ID = #{sbjctId} AND NVL(DELYN,'N') = 'N' ), ASMT_SUB AS ( SELECT S.USER_ID , COUNT(DISTINCT S.ASMT_ID) AS ASMT_SBMSN_CNT FROM TB_LMS_ASMT_SBMSN S JOIN TB_LMS_ASMT M ON M.ASMT_ID = S.ASMT_ID WHERE M.SBJCT_ID = #{sbjctId} AND NVL(M.DELYN,'N') = 'N' AND NVL(S.DELYN,'N') = 'N' AND S.SBMSN_DTTM IS NOT NULL GROUP BY S.USER_ID ), QA_STATS AS ( SELECT A.USER_ID , COUNT(CASE WHEN A.UP_ATCL_ID IS NULL AND NVL(A.DELYN,'N')='N' THEN 1 END) AS QA_REG_CNT , COUNT(CASE WHEN A.UP_ATCL_ID IS NOT NULL AND NVL(A.DELYN,'N')='N' THEN 1 END) AS QA_ANS_CNT FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON B.BBS_ID = A.BBS_ID WHERE B.SBJCT_ID = #{sbjctId} AND NVL(B.DELYN,'N')='N' AND NVL(A.DELYN,'N')='N' GROUP BY A.USER_ID ), TALK_STATS AS ( SELECT C.USER_ID , COUNT(*) AS TALK_REPLY_CNT FROM TB_LMS_DSCS_CMNT C JOIN TB_LMS_DSCS_ATCL A ON A.DSCS_ATCL_ID = C.DSCS_ATCL_ID JOIN TB_LMS_DSCS D ON D.DSCS_ID = A.DSCS_ID WHERE D.SBJCT_ID = #{sbjctId} AND NVL(D.DELYN,'N')='N' AND NVL(C.DELYN,'N')='N' GROUP BY C.USER_ID ), SRVY_TOT AS ( SELECT COUNT(*) AS SRVY_TOT_CNT FROM TB_LMS_SRVY WHERE SBJCT_ID = #{sbjctId} AND NVL(DELYN,'N')='N' AND NVL(USEYN,'Y')='Y' ), SRVY_SUB AS ( SELECT P.USER_ID , COUNT(DISTINCT P.SRVY_ID) AS SRVY_SBMSN_CNT FROM TB_LMS_SRVY_PTCP P JOIN TB_LMS_SRVY S ON S.SRVY_ID = P.SRVY_ID WHERE S.SBJCT_ID = #{sbjctId} AND NVL(S.DELYN,'N')='N' GROUP BY P.USER_ID ), DSCC_TOT AS ( SELECT COUNT(*) AS DSCC_TOT_CNT FROM TB_LMS_DSCS WHERE SBJCT_ID = #{sbjctId} AND NVL(DELYN,'N')='N' ), DSCC_SUB AS ( SELECT A.USER_ID , COUNT(DISTINCT A.DSCS_ID) AS DSCC_SBMSN_CNT FROM TB_LMS_DSCS_ATCL A JOIN TB_LMS_DSCS D ON D.DSCS_ID = A.DSCS_ID WHERE D.SBJCT_ID = #{sbjctId} AND NVL(D.DELYN,'N')='N' AND NVL(A.DELYN,'N')='N' AND A.ATCL_LV = 1 GROUP BY A.USER_ID ), QUIZ_TOT AS ( SELECT COUNT(DISTINCT B.EXAM_BSC_ID) AS QUIZ_TOT_CNT FROM TB_LMS_EXAM_BSC B JOIN TB_LMS_EXAM_DTL D ON D.EXAM_BSC_ID = B.EXAM_BSC_ID WHERE B.SBJCT_ID = #{sbjctId} AND B.EXAM_TYCD='QUIZ' AND NVL(B.DELYN,'N')='N' AND NVL(B.USEYN,'Y')='Y' ), QUIZ_SUB AS ( SELECT T.USER_ID , COUNT(DISTINCT B.EXAM_BSC_ID) AS QUIZ_SBMSN_CNT FROM TB_LMS_TKEXAM T JOIN TB_LMS_EXAM_DTL D ON D.EXAM_DTL_ID = T.EXAM_DTL_ID JOIN TB_LMS_EXAM_BSC B ON B.EXAM_BSC_ID = D.EXAM_BSC_ID WHERE B.SBJCT_ID = #{sbjctId} AND B.EXAM_TYCD='QUIZ' AND NVL(B.DELYN,'N')='N' AND NVL(B.USEYN,'Y')='Y' AND T.TKEXAM_CMPTNYN='Y' GROUP BY T.USER_ID ), EXAM_SCR AS ( SELECT T.USER_ID , MAX(CASE WHEN NVL(B.EXAM_TTL,'') LIKE '%중간%' THEN R.TOT_SCR END) AS MID_SCORE , MAX(CASE WHEN NVL(B.EXAM_TTL,'') LIKE '%기말%' THEN R.TOT_SCR END) AS FINAL_SCORE FROM TB_LMS_TKEXAM T JOIN TB_LMS_TKEXAM_RSLT R ON R.TKEXAM_ID = T.TKEXAM_ID AND R.USER_ID = T.USER_ID JOIN TB_LMS_EXAM_DTL D ON D.EXAM_DTL_ID = T.EXAM_DTL_ID JOIN TB_LMS_EXAM_BSC B ON B.EXAM_BSC_ID = D.EXAM_BSC_ID WHERE B.SBJCT_ID = #{sbjctId} AND B.EXAM_TYCD='EXAM' AND NVL(B.DELYN,'N')='N' AND NVL(B.USEYN,'Y')='Y' GROUP BY T.USER_ID ) SELECT ROW_NUMBER() OVER(ORDER BY U.STDNT_NO ASC) AS lineNo , COUNT(1) OVER() AS totalCnt , U.USER_ID AS userId , U.USERNM AS usernm , U.STDNT_NO AS stdntNo , D.DEPTNM AS deptnm , NVL(QA.QA_ANS_CNT, 0) AS qaAnsCnt , NVL(QA.QA_REG_CNT, 0) AS qaRegCnt , NVL(TK.TALK_REPLY_CNT, 0) AS talkReplyCnt , NVL(ASB.ASMT_SBMSN_CNT, 0) AS asmtSbmsnCnt , NVL(AT.ASMT_TOT_CNT, 0) AS asmtTrgtCnt , NVL(QS.QUIZ_SBMSN_CNT, 0) AS quizSbmsnCnt , NVL(QT.QUIZ_TOT_CNT, 0) AS quizTrgtCnt , NVL(SS.SRVY_SBMSN_CNT, 0) AS srvySbmsnCnt , NVL(ST2.SRVY_TOT_CNT, 0) AS srvyTrgtCnt , NVL(DS.DSCC_SBMSN_CNT, 0) AS dsccSbmsnCnt , NVL(DT.DSCC_TOT_CNT, 0) AS dsccTrgtCnt , ES.MID_SCORE AS midScore , ES.FINAL_SCORE AS finalScore FROM BASE_STDNT BS JOIN TB_LMS_USER U ON U.USER_ID = BS.USER_ID JOIN TB_LMS_DEPT D ON D.DEPT_ID = U.DEPT_ID LEFT JOIN ASMT_TOT AT ON 1 = 1 LEFT JOIN ASMT_SUB ASB ON ASB.USER_ID = U.USER_ID LEFT JOIN QA_STATS QA ON QA.USER_ID = U.USER_ID LEFT JOIN TALK_STATS TK ON TK.USER_ID = U.USER_ID LEFT JOIN QUIZ_TOT QT ON 1 = 1 LEFT JOIN QUIZ_SUB QS ON QS.USER_ID = U.USER_ID LEFT JOIN SRVY_TOT ST2 ON 1 = 1 LEFT JOIN SRVY_SUB SS ON SS.USER_ID = U.USER_ID LEFT JOIN DSCC_TOT DT ON 1 = 1 LEFT JOIN DSCC_SUB DS ON DS.USER_ID = U.USER_ID LEFT JOIN EXAM_SCR ES ON ES.USER_ID = U.USER_ID WHERE 1=1
AND U.ORG_ID = #{orgId}
AND ( LOWER(U.USERNM) LIKE FN_LIKE_VAL(LOWER(#{keyword})) OR U.STDNT_NO LIKE FN_LIKE_VAL(#{keyword}) OR LOWER(D.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{keyword})) )

SELECT COUNT(*)
FROM TB_LMS_LOG_USER_ACTV L
         JOIN TB_LMS_ATNDLC A
              ON A.USER_ID = L.USER_ID
WHERE L.SBJCT_OFRNG_ID = #{sbjctId}
  AND L.USER_ID = #{userId}

mapper.update:
UPDATE TB_LMS_ATNDLC
SET ATNDLC_STSCD = 'FORCE'
  , MDFR_ID      = #{mdfrId}
  , MOD_DTTM     = SYSDATE
WHERE SBJCT_ID = #{sbjctId}
  AND USER_ID = #{userId}

UPDATE TB_LMS_ATNDLC
SET ATNDLC_STSCD = NULL
  , MDFR_ID      = #{mdfrId}
  , MOD_DTTM     = SYSDATE
WHERE SBJCT_ID = #{sbjctId}
  AND USER_ID = #{userId}
